```cpp
#include <iostream>
#include <memory>

class DataBuffer {
public:
    DataBuffer(int size) : buffer(new int[size]) {
        std::cout << "Buffer allocated" << std::endl;
    }
    ~DataBuffer() {
        delete[] buffer;
        std::cout << "Buffer deallocated" << std::endl;
    }
    void process() {
        std::cout << "Processing data..." << std::endl;
    }
private:
    int* buffer;
};

void runTask() {
    try {
        DataBuffer* task = std::make_shared<DataBuffer>(1024);
        task->process();
    } catch (std::bad_alloc& e) {
        std::cerr << "Memory allocation failed: " << e.what() << std::endl;
    }
}

int main() {
    try {
        for(int i = 0; i < 1000; i++) {
            runTask();
        }
    } catch (std::bad_alloc& e) {
        std::cerr << "Memory allocation failed in main: " << e.what() << std::endl;
    }
    return 0;
}
